  'Ho Chi Minh City': [106.7, 10.8], 'Hanoi': [105.9, 21.0], 'Istanbul': [29.0, 41.1],
  'Ankara': [32.9, 39.9], 'Cairo': [31.2, 30.0], 'Alexandria': [29.9, 31.2],
  'Lagos': [3.4, 6.5], 'Abuja': [7.5, 9.1], 'Nairobi': [36.8, -1.3],
  'Cape Town': [18.4, -33.9], 'Johannesburg': [28.0, -26.2], 'Durban': [31.0, -29.9],
  'Casablanca': [-7.6, 33.5], 'Rabat': [-6.8, 34.0], 'Tunis': [10.2, 36.8],
  'Algiers': [3.0, 36.8], 'Kinshasa': [15.3, -4.3], 'Lagos City': [3.4, 6.5],
  'Addis Ababa': [38.7, 9.0], 'Dar es Salaam': [39.3, -6.8], 'Luanda': [13.2, -8.8],
  'Harare': [31.1, -17.8], 'Tel Aviv': [34.8, 32.1], 'Riyadh': [46.7, 24.7],
  'Jeddah': [39.2, 21.5], 'Dubai': [55.3, 25.2], 'Abu Dhabi': [54.4, 24.5],
